"    private const val SAMPLE_RATE = 22050
    private const val SYNTH_VERSION = 2

    @Volatile
    var volumeScale: Float = 1.0f

    private enum class Effect { POP, WHOOSH, SIZZLE, DRIFT, CHIME, FANFARE }

    @Volatile
    private var pool: SoundPool? = null
    private val soundIds = ConcurrentHashMap<Effect, Int>()
    private val readySamples = ConcurrentHashMap<Int, Boolean>()

    /** Call once from MainActivity.onCreate. Idempotent; renders off-thread. */
    fun init(context: Context) {
        if (pool != null) return
        val p = SoundPool.Builder()
            .setMaxStreams(4)
            .setAudioAttributes(
                AudioAttributes.Builder()
                    .setUsage(AudioAttributes.USAGE_GAME)
                    .setContentType(AudioAttributes.CONTENT_TYPE_SONIFICATION)
                    .build()
            )
            .build()
        p.setOnLoadCompleteListener { _, sampleId, status ->
            if (status == 0) readySamples[sampleId] = true
        }
        pool = p
        val cacheDir = context.applicationContext.cacheDir
        // One short-lived render thread at startup — not one per tap.
        Thread {
            try {
                val prefix = "synth_v${SYNTH_VERSION}_"
                cacheDir.listFiles()?.forEach { file ->
                    if (file.name.startsWith("synth_") && !file.name.startsWith(prefix)) {
                        file.delete()
                    }
                }
                for (effect in Effect.entries) {
                    val file = File(cacheDir, "synth_v${SYNTH_VERSION}_${effect.name.lowercase()}.wav")
                    if (!file.exists() || file.length() == 0L) writeWav(file, render(effect))
                    soundIds[effect] = p.load(file.absolutePath, 1)
                }
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }.start()
    }"

