"package com.example.sophiaspace.ui.sky

import com.example.sophiaspace.sky.Ephemeris
import org.junit.Assert.assertEquals
import org.junit.Assert.assertNull
import org.junit.Test

class SkyViewTest {

    @Test
    fun `findNearestPlanet returns nearest planet within radius`() {
        val planets = listOf(
            Triple(Ephemeris.Planet.JUPITER, 12.0, 180.0),
            Triple(Ephemeris.Planet.VENUS, 14.0, 180.0)
        )
        val nearest = findNearestPlanet(planets, 10.0, 180.0)
        assertEquals(Ephemeris.Planet.JUPITER, nearest)
    }

    @Test
    fun `findNearestPlanet returns nearest planet even if declaration order is reversed`() {
        val planets = listOf(
            Triple(Ephemeris.Planet.VENUS, 14.0, 180.0),
            Triple(Ephemeris.Planet.JUPITER, 12.0, 180.0)
        )
        val nearest = findNearestPlanet(planets, 10.0, 180.0)
        assertEquals(Ephemeris.Planet.JUPITER, nearest)
    }

    @Test
    fun `findNearestPlanet returns null if all planets exceed max radius`() {
        val planets = listOf(
            Triple(Ephemeris.Planet.JUPITER, 20.0, 180.0)
        )
        val nearest = findNearestPlanet(planets, 10.0, 180.0, maxRadiusDeg = 6.0)
        assertNull(nearest)
    }

    @Test
    fun `findNearestPlanet ignores planets below minimum altitude`() {
        val planets = listOf(
            Triple(Ephemeris.Planet.JUPITER, 1.0, 180.0)
        )
        val nearest = findNearestPlanet(planets, 2.0, 180.0, minAltitudeDeg = 5.0)
        assertNull(nearest)
    }
}
"

